          ctx.font = 'italic 40px "Cormorant Garamond", serif';
          ctx.fillText('[ Thảo mộc & Đồ nghề ]', canvas.width / 2, 800);
          
          // Tải ảnh ngầm và vẽ đè lên trang sách khi tải xong
